const item = $input.first().json;
const body = item.body || item;
const msgs = body.messages || [];
const msg = msgs[0] || {};
const textBody = msg.text?.body || msg.caption || body.text || body.caption || '';
const isJunk = textBody.length < 20 || /sticker|audio|voice|gif/i.test(msg.type || '');

function getPhone(val) {
  if (!val) return null;
  if (typeof val === 'object') val = val.id || val.phone || val.number || JSON.stringify(val);
  let s = String(val);
  if (s.includes('wa.me/')) s = s.split('wa.me/')[1].split('?')[0];
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7 && digits.length <= 15) ? digits : null;
}

const sc = getPhone(msg.from) || getPhone(msg.author) || getPhone(msg.participant) || getPhone(body.from) || getPhone(body.contact) || "No disponible";
const sourceChatId = msg.chat_id || body.chatId || body.from || null;
const isGroup = typeof sourceChatId === 'string' ? sourceChatId.endsWith('@g.us') : false;

return {
  ...item,
  platform: "WhatsApp",
  sender_contact: sc,
  final_contact: sc,
  from_name: msg.from_name || '',
  chat_name: msg.chat_name || '',
  source_chat_id: sourceChatId,
  is_group_source: isGroup,
  texto_limpio: textBody.trim(),
  looksValuable: !isJunk,
  message_type: msg.type || 'text',
  channel_id: body.channel_id || ''
};

