function norm(v) { return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio || "");
  const sender = String(data.final_contact || data.sender_contact || "").replace(/\D/g, "").replace(/^0+/, "");

  let rejectReason = null;
  let spamScore = 0;

  const hardHits = [...HARD_BLOCK].some(k => text.includes(k));
  const softHits = [...SOFT_BLOCK].filter(k => text.includes(k)).length;
  let positiveHits = [...POSITIVE].filter(k => text.includes(k)).length;

  // New Heuristic: Detect money and time (Universal signals)
  const hasMoney = /[€$£]|usd|eur|gbp|\d+\s?k/i.test(text);
  const hasTime = /tonight|overnight|today|tomorrow|hour|hora|lunes|martes|miercoles|jueves|viernes|sabado|domingo/i.test(text);

  if (hasMoney) positiveHits += 2;
  if (hasTime) positiveHits += 1;

  const links = (text.match(/https?:\/\/|wa\.me\/|t\.me\/|telegram/gi) || []).length;
  const phones = (text.match(/\+?\d[\d\s\-()]{6,}/g) || []).length;
  const emojis = (text.match(/[\p{Extended_Pictographic}]/gu) || []).length;
  const tooShort = text.trim().length < 20;

  if (BANNED_SENDERS.has(sender)) rejectReason = "sender_banned";
  else if (sender && BANNED_PREFIXES.some(p => sender.startsWith(p))) rejectReason = "prefix_banned";

  if (!rejectReason) {
    if (hardHits) spamScore += 100;
    if (softHits >= 2) spamScore += 30;
    if (links >= 5) spamScore += 30;
    if (phones >= 4) spamScore += 30;
    if (emojis >= 15) spamScore += 20;
    if (tooShort) spamScore += 20;
    if (positiveHits === 0) spamScore += 50;

    if (spamScore >= 80) rejectReason = "high_spam_score";
  }

  const isValuable = data.looksValuable !== false && !rejectReason;
  results.push({ json: { ...data, looksValuable: isValuable, reject_reason: rejectReason, spamScore, positiveHits } });
}
return results;

const crypto = require('crypto');
const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];
if (!store.lastSenders) store.lastSenders = {};

const now = Date.now();
const TTL = 86400000;
const BURST_WINDOW = 120000;

store.history = store.history.filter(h => now - h.time < TTL);

function getHash(text) {
  return crypto.createHash('md5').update(String(text || "").toLowerCase().trim()).digest('hex');
}

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "").replace(/\D/g, "");
  const fp = getHash(data.texto_limpio);

  let isDuplicate = false;

  if (sender && store.lastSenders[sender] && (now - store.lastSenders[sender].time < BURST_WINDOW)) {
    isDuplicate = true;
  }
  if (!isDuplicate) {
    isDuplicate = store.history.some(h => h.fp === fp);
  }

  if (!isDuplicate) {
    store.history.push({ time: now, sender, fp });
    if (sender) store.lastSenders[sender] = { time: now };
    results.push(item);
  }
}
return results;

try {
  const input = $input.first().json;
  const meta = $("Dedup Hash").first().json;

  let rawText = input.text || input.output || input.result || input.response?.text || input.response || input.data?.text || input.data?.content || input.output?.content || input.content || input.choices?.[0]?.message?.content || "";

  if (!rawText && typeof input === 'object') {
    const deepSearch = JSON.stringify(input);
    const match = deepSearch.match(/"content":"([^"]+)"/);
    if (match) rawText = match[1];
  }

  let cleaned = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  let jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonMatch[0] = jsonMatch[0].replace(/\n/g, ' ').replace(/\r/g, ' ');

  let jsonStr = jsonMatch ? jsonMatch[0] : "";
  let parsed = {};
  if (!jsonStr) return [{ json: { ...meta, trash: true, category: 'trash', debug_raw: rawText } }];

  try { parsed = JSON.parse(jsonStr); }
  catch (ex) { return [{ json: { ...meta, trash: true, category: 'trash' } }]; }

  function cleanContact(value) {
    if (!value || value === "Unknown") return null;
    if (typeof value === 'object') value = value.id || value.phone || value.number || JSON.stringify(value);
    const digits = String(value).replace(/[^0-9]/g, '');
    return digits.length >= 7 ? `+${digits}` : null;
  }

  const originalClean = cleanContact(meta.final_contact) || cleanContact(meta.sender_contact);
  let normalizedContact = originalClean || null;
  if (!normalizedContact && parsed.contact && parsed.contact !== 'Phone') normalizedContact = cleanContact(parsed.contact);

  const isTrash = parsed.category === 'trash' || parsed.trash === true;
  return [{ json: { ...meta, ...parsed, contact: normalizedContact, final_contact: normalizedContact || meta.final_contact, trash: isTrash } }];
} catch(e) { return [{json:{ trash:true, category:'trash', debug_error: e.message }}]; }

const item = $json;
const text = String(item.text_es || "").toLowerCase();
const city = String(item.city || "").trim().toLowerCase();
const category = String(item.category || "").trim().toLowerCase();

const POSITIVE = ["apartamento", "plaza", "agency", "agencia", "club", "booking", "tour", "models", "vacante", "malta", "london", "dubai"];
const NEGATIVE = ["crypto", "forex", "casino", "bank", "loan", "call center"];

const positiveHits = POSITIVE.filter(k => text.includes(k)).length;
const negativeHits = NEGATIVE.filter(k => text.includes(k)).length;
const hasGoodCity = !!city && city !== "global" && city !== "unknown";

let reject = false, reason = null;

if (category === "trash") { reject = true; reason = "ai_trash"; }
else if (negativeHits >= 1 && positiveHits === 0) { reject = true; reason = "negative_signal"; }
else if (!hasGoodCity && text.length < 150) { reject = true; reason = "weak_lead"; }

return { ...item, looksValuableFinal: !reject, reject_reason_final: reason, postPositiveHits: positiveHits };

const store = $getWorkflowStaticData('global');

if (!store.users) store.users = {};
if (!store.banned) store.banned = {};

const results = [];
const now = Date.now();

// Configuración del sistema de Auto-Ban
const BAN_TIME = 24 * 60 * 60 * 1000; // 24 horas
const MIN_MSGS = 5; // Mínimo de mensajes para evaluar ban
const MAX_BAD_RATIO = 0.7; // Si el 70% o más de sus mensajes son basura (trash), se banea
const WHITELIST = new Set(["346xxxxxxx", "admin_id"]);

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "unknown");

  // Si está en whitelist, pasa siempre sin contar
  if (WHITELIST.has(sender)) {
    results.push(item);
    continue;
  }

  // Si no existe, inicializar usuario
  if (!store.users[sender]) {
    store.users[sender] = {
      good: 0,
      bad: 0,
      total: 0
    };
  }

  // Revisar si ya está baneado
  if (store.banned[sender]) {
    const ban = store.banned[sender];
    if (now < ban.until) {
      data.looksValuableFinal = false; // Forzamos el bloqueo
      data.reject_reason_final = "user_auto_banned";
      results.push(item);
      continue;
    } else {
      // El ban expiró, le damos otra oportunidad
      delete store.banned[sender];
      store.users[sender] = { good: 0, bad: 0, total: 0 };
    }
  }

  const user = store.users[sender];
  user.total += 1;

  // Evaluar si este mensaje actual es basura o bueno (según el nodo anterior)
  if (data.looksValuableFinal === false || data.trash === true) {
    user.bad += 1;
  } else {
    user.good += 1;
  }

  // Evaluar Ban si supera el umbral de mensajes enviados
  if (user.total >= MIN_MSGS) {
    const ratio = user.bad / user.total;
    if (ratio >= MAX_BAD_RATIO) {
      store.banned[sender] = {
        until: now + BAN_TIME,
        reason: "high_spam_ratio",
        stats: { ...user }
      };
      // Marcamos el mensaje actual para que no pase
      data.looksValuableFinal = false;
      data.reject_reason_final = "user_just_banned";
    }
  }

  results.push(item);
}

return results;

